+
+          // Make shell scripts executable
+          if (file.endsWith('.sh')) {
+            fs.chmodSync(destPath, '755');
+          }
+
+          result.created.files.push(`.claude/helpers/${file}`);
+        } else {
+          result.skipped.push(`.claude/helpers/${file}`);
+        }
+      }
+      return; // Skip generating if we copied from source
